<script setup lang="ts">
import { AlertTriangle, Lightbulb } from 'lucide-vue-next'
import type { GapSuggestion } from '@/types/resume'

defineProps<{
  suggestions: GapSuggestion[]
}>()

function gapColor(gap: string) {
  if (gap === '完全缺失') return 'text-red-400 bg-red-400/10'
  if (gap === '严重') return 'text-orange-400 bg-orange-400/10'
  if (gap === '中等') return 'text-accent-amber bg-accent-amber/10'
  return 'text-emerald-400 bg-emerald-400/10'
}
</script>

<template>
  <div class="glass-card p-5">
    <div class="mb-4 flex items-center gap-2">
      <Lightbulb class="h-5 w-5 text-accent-amber" />
      <h3 class="font-display text-base font-semibold text-slate-50">短板 & 改进建议</h3>
    </div>

    <div class="overflow-x-auto">
      <table class="w-full text-left text-sm">
        <thead>
          <tr class="border-b border-white/10 text-xs uppercase tracking-wider text-muted">
            <th class="pb-3 pl-2 font-medium">技能</th>
            <th class="pb-3 font-medium">差距</th>
            <th class="pb-3 font-medium">建议行动</th>
          </tr>
        </thead>
        <tbody class="divide-y divide-white/5">
          <tr v-for="item in suggestions" :key="item.skill" class="group">
            <td class="py-4 pl-2">
              <div class="flex items-center gap-2">
                <AlertTriangle
                  class="h-4 w-4"
                  :class="item.gap === '完全缺失' || item.gap === '严重' ? 'text-red-400' : 'text-accent-amber'"
                />
                <span class="font-medium text-slate-200">{{ item.skill }}</span>
              </div>
            </td>
            <td class="py-4">
              <span class="rounded-md px-2 py-1 text-xs font-medium" :class="gapColor(item.gap)">
                {{ item.gap }}
              </span>
            </td>
            <td class="py-4">
              <ul class="space-y-1">
                <li
                  v-for="(action, idx) in item.actions"
                  :key="idx"
                  class="flex items-start gap-2 text-slate-400"
                >
                  <span class="mt-1.5 h-1 w-1 flex-shrink-0 rounded-full bg-accent-blue" />
                  {{ action }}
                </li>
              </ul>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</template>
