<script setup lang="ts">
defineProps<{
  domains: string[]
  modelValue: string
}>()

const emit = defineEmits<{
  (e: 'update:modelValue', value: string): void
}>()
</script>

<template>
  <div class="flex flex-wrap gap-2">
    <button
      v-for="domain in domains"
      :key="domain"
      class="rounded-xl px-4 py-2 text-sm font-medium transition-all"
      :class="
        modelValue === domain
          ? 'bg-accent-blue/10 text-accent-blue shadow-glow'
          : 'border border-white/10 bg-white/5 text-slate-300 hover:border-white/20 hover:text-slate-100'
      "
      @click="emit('update:modelValue', domain)"
    >
      {{ domain }}
    </button>
  </div>
</template>
